package com.dataprocessing.grpc;

import io.grpc.Server;
import io.grpc.ServerBuilder;
import io.grpc.netty.shaded.io.grpc.netty.GrpcSslContexts;
import io.grpc.netty.shaded.io.grpc.netty.NettyServerBuilder;
import io.grpc.netty.shaded.io.netty.handler.ssl.SslContext;
import io.grpc.netty.shaded.io.netty.handler.ssl.SslContextBuilder;
import io.grpc.netty.shaded.io.netty.handler.ssl.ClientAuth;

import java.io.File;
import java.io.IOException;
import java.util.concurrent.TimeUnit;
import java.util.logging.Level;
import java.util.logging.Logger;

public class GrpcServer {

    private static final Logger logger = Logger.getLogger(GrpcServer.class.getName());
    private static final int PORT = 9090;
    private static final int MAX_INBOUND_MESSAGE_SIZE = 100 * 1024 * 1024; // 100MB
    private static final int MAX_INBOUND_METADATA_SIZE = 8 * 1024; // 8KB
    private static final int MAX_CONCURRENT_CALLS_PER_CONNECTION = 100;
    private static final long KEEPALIVE_TIME_SECONDS = 60;
    private static final long KEEPALIVE_TIMEOUT_SECONDS = 20;
    private static final long MAX_CONNECTION_IDLE_SECONDS = 300;
    private static final long MAX_CONNECTION_AGE_SECONDS = 3600;

    private Server server;

    public void start() throws IOException {
        SslContext sslContext = buildSslContext();

        server = NettyServerBuilder.forPort(PORT)
                .sslContext(sslContext)
                .addService(new FileTransferServiceImpl())
                .addService(new AuthInterceptedService())
                .maxInboundMessageSize(MAX_INBOUND_MESSAGE_SIZE)
                .maxInboundMetadataSize(MAX_INBOUND_METADATA_SIZE)
                .maxConcurrentCallsPerConnection(MAX_CONCURRENT_CALLS_PER_CONNECTION)
                .keepAliveTime(KEEPALIVE_TIME_SECONDS, TimeUnit.SECONDS)
                .keepAliveTimeout(KEEPALIVE_TIMEOUT_SECONDS, TimeUnit.SECONDS)
                .maxConnectionIdle(MAX_CONNECTION_IDLE_SECONDS, TimeUnit.SECONDS)
                .maxConnectionAge(MAX_CONNECTION_AGE_SECONDS, TimeUnit.SECONDS)
                .permitKeepAliveWithoutCalls(false)
                .permitKeepAliveTime(30, TimeUnit.SECONDS)
                .build()
                .start();

        logger.info("gRPC Server started on port " + PORT + " with TLS");

        Runtime.getRuntime().addShutdownHook(new Thread(() -> {
            logger.info("Shutting down gRPC server...");
            try {
                GrpcServer.this.stop();
            } catch (InterruptedException e) {
                Thread.currentThread().interrupt();
                logger.log(Level.SEVERE, "Server shutdown interrupted", e);
            }
            logger.info("Server shut down.");
        }));
    }

    private SslContext buildSslContext() throws IOException {
        String certChainPath = System.getenv("GRPC_TLS_CERT_CHAIN");
        String privateKeyPath = System.getenv("GRPC_TLS_PRIVATE_KEY");
        String trustCertPath = System.getenv("GRPC_TLS_TRUST_CERT");

        if (certChainPath == null || privateKeyPath == null) {
            throw new IllegalStateException(
                    "TLS certificate configuration required. Set GRPC_TLS_CERT_CHAIN and GRPC_TLS_PRIVATE_KEY environment variables.");
        }

        SslContextBuilder sslContextBuilder = SslContextBuilder
                .forServer(new File(certChainPath), new File(privateKeyPath));

        if (trustCertPath != null) {
            sslContextBuilder.trustManager(new File(trustCertPath))
                    .clientAuth(ClientAuth.REQUIRE);
        }

        return GrpcSslContexts.configure(sslContextBuilder).build();
    }

    public void stop() throws InterruptedException {
        if (server != null) {
            server.shutdown().awaitTermination(30, TimeUnit.SECONDS);
            if (!server.isTerminated()) {
                server.shutdownNow();
            }
        }
    }

    public void blockUntilShutdown() throws InterruptedException {
        if (server != null) {
            server.awaitTermination();
        }
    }

    public static void main(String[] args) throws IOException, InterruptedException {
        GrpcServer grpcServer = new GrpcServer();
        grpcServer.start();
        grpcServer.blockUntilShutdown();
    }
}

