package com.dataprocessing.grpc;

import io.grpc.*;

import java.util.logging.Logger;

public class AuthInterceptor implements ServerInterceptor {

    private static final Logger logger = Logger.getLogger(AuthInterceptor.class.getName());
    private static final Metadata.Key<String> AUTH_TOKEN_KEY =
            Metadata.Key.of("authorization", Metadata.ASCII_STRING_MARSHALLER);

    @Override
    public <ReqT, RespT> ServerCall.Listener<ReqT> interceptCall(
            ServerCall<ReqT, RespT> call,
            Metadata headers,
            ServerCallHandler<ReqT, RespT> next) {

        String authToken = headers.get(AUTH_TOKEN_KEY);

        if (authToken == null || !validateToken(authToken)) {
            call.close(Status.UNAUTHENTICATED.withDescription("Invalid or missing authentication token"), new Metadata());
            return new ServerCall.Listener<ReqT>() {};
        }

        return next.startCall(call, headers);
    }

    private boolean validateToken(String token) {
        // Implement proper token validation (JWT verification, etc.)
        // This is a placeholder - replace with actual authentication logic
        if (token == null || token.isEmpty()) {
            return false;
        }

        if (token.startsWith("Bearer ")) {
            String actualToken = token.substring(7);
            // Validate JWT or API key here
            return !actualToken.isEmpty();
        }

        return false;
    }
}

