package com.dataprocessing.grpc;

import io.grpc.*;

import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.atomic.AtomicInteger;
import java.util.concurrent.atomic.AtomicLong;
import java.util.logging.Logger;

public class RateLimitInterceptor implements ServerInterceptor {

    private static final Logger logger = Logger.getLogger(RateLimitInterceptor.class.getName());
    private static final int MAX_REQUESTS_PER_MINUTE = 1000;
    private static final long WINDOW_MS = 60_000;

    private final ConcurrentHashMap<String, RateCounter> rateLimiters = new ConcurrentHashMap<>();

    @Override
    public <ReqT, RespT> ServerCall.Listener<ReqT> interceptCall(
            ServerCall<ReqT, RespT> call,
            Metadata headers,
            ServerCallHandler<ReqT, RespT> next) {

        String clientId = call.getAttributes().get(Grpc.TRANSPORT_ATTR_REMOTE_ADDR) != null
                ? call.getAttributes().get(Grpc.TRANSPORT_ATTR_REMOTE_ADDR).toString()
                : "unknown";

        RateCounter counter = rateLimiters.computeIfAbsent(clientId, k -> new RateCounter());

        if (!counter.tryAcquire()) {
            call.close(Status.RESOURCE_EXHAUSTED.withDescription("Rate limit exceeded"), new Metadata());
            return new ServerCall.Listener<ReqT>() {};
        }

        return next.startCall(call, headers);
    }

    private static class RateCounter {
        private final AtomicInteger count = new AtomicInteger(0);
        private final AtomicLong windowStart = new AtomicLong(System.currentTimeMillis());

        boolean tryAcquire() {
            long now = System.currentTimeMillis();
            long start = windowStart.get();

            if (now - start > WINDOW_MS) {
                if (windowStart.compareAndSet(start, now)) {
                    count.set(0);
                }
            }

            return count.incrementAndGet() <= MAX_REQUESTS_PER_MINUTE;
        }
    }
}

