import io.grpc.netty.shaded.io.grpc.netty.NettyChannelBuilder;
import io.grpc.netty.shaded.io.netty.handler.ssl.SslContext;
import io.grpc.stub.MetadataUtils;
import io.grpc.stub.StreamObserver;

import java.io.*;
import java.nio.file.Files;
import java.nio.file.Path;
import java.security.MessageDigest;
import java.util.HexFormat;
import java.util.concurrent.CountDownLatch;
import java.util.concurrent.TimeUnit;
import java.util.logging.Level;
import java.util.logging.Logger;

public class GrpcClient {

    private static final Logger logger = Logger.getLogger(GrpcClient.class.getName());
    private static final int CHUNK_SIZE = 64 * 1024;
    private static final int MAX_INBOUND_MESSAGE_SIZE = 100 * 1024 * 1024;

    private final ManagedChannel channel;
    private final FileTransferServiceGrpc.FileTransferServiceStub asyncStub;
    private final FileTransferServiceGrpc.FileTransferServiceBlockingStub blockingStub;

    public GrpcClient(String host, int port, String authToken) throws Exception {
        String trustCertPath = System.getenv("GRPC_TLS_TRUST_CERT");

        SslContext sslContext;
        if (trustCertPath != null) {
            sslContext = GrpcSslContexts.forClient()
                    .trustManager(new File(trustCertPath))
                    .build();
        } else {
            sslContext = GrpcSslContexts.forClient().build();
        }

        channel = NettyChannelBuilder.forAddress(host, port)
                .sslContext(sslContext)
                .maxInboundMessageSize(MAX_INBOUND_MESSAGE_SIZE)
                .build();

        Metadata metadata = new Metadata();
        Metadata.Key<String> authKey = Metadata.Key.of("authorization", Metadata.ASCII_STRING_MARSHALLER);
        metadata.put(authKey, "Bearer " + authToken);

        asyncStub = FileTransferServiceGrpc.newStub(channel)
                .withInterceptors(MetadataUtils.newAttachHeadersInterceptor(metadata));
        blockingStub = FileTransferServiceGrpc.newBlockingStub(channel)
                .withInterceptors(MetadataUtils.newAttachHeadersInterceptor(metadata));
    }

    public void uploadFile(Path filePath) throws Exception {
        if (!Files.exists(filePath) || !Files.isRegularFile(filePath)) {
            throw new IllegalArgumentException("File does not exist or is not a regular file: " + filePath);
        }

        String filename = filePath.getFileName().toString();
        CountDownLatch latch = new CountDownLatch(1);

        StreamObserver<UploadStatus> responseObserver = new StreamObserver<UploadStatus>() {
            @Override
            public void onNext(UploadStatus status) {
                logger.info("Upload status: " + status.getMessage() +
                        " (bytes: " + status.getBytesReceived() + ")");
            }

            @Override
            public void onError(Throwable t) {
                logger.log(Level.SEVERE, "Upload failed", t);
                latch.countDown();
            }

            @Override
            public void onCompleted() {
                logger.info("Upload stream completed");
                latch.countDown();
            }
        };

        StreamObserver<FileChunk> requestObserver = asyncStub.uploadFile(responseObserver);

        try (InputStream inputStream = new BufferedInputStream(new FileInputStream(filePath.toFile()))) {
            byte[] buffer = new byte[CHUNK_SIZE];
            int bytesRead;
            long offset = 0;

            while ((bytesRead = inputStream.read(buffer)) != -1) {
                byte[] chunkData = new byte[bytesRead];
                System.arraycopy(buffer, 0, chunkData, 0, bytesRead);

                MessageDigest digest = MessageDigest.getInstance("SHA-256");
                String checksum = HexFormat.of().formatHex(digest.digest(chunkData));

                FileChunk chunk = FileChunk.newBuilder()
                        .setFilename(filename)
                        .setContent(com.google.protobuf.ByteString.copyFrom(chunkData))
                        .setOffset(offset)
                        .setChecksum(checksum)
                        .build();

                requestObserver.onNext(chunk);
                offset += bytesRead;
            }

            requestObserver.onCompleted();
        } catch (Exception e) {
            requestObserver.onError(e);
            throw e;
        }

        if (!latch.await(5, TimeUnit.MINUTES)) {
            logger.warning("Upload timed out");
        }
    }

    public void downloadFile(String filename, Path outputPath) throws Exception {
        CountDownLatch latch = new CountDownLatch(1);

        FileRequest request = FileRequest.newBuilder()
                .setFilename(filename)
                .build();

        try (OutputStream outputStream = new BufferedOutputStream(new FileOutputStream(outputPath.toFile()))) {
            asyncStub.downloadFile(request, new StreamObserver<FileChunk>() {
                @Override
                public void onNext(FileChunk chunk) {
                    try {
                        if (!chunk.getIsLastChunk()) {
                            byte[] content = chunk.getContent().toByteArray();

                            // Verify chunk checksum
                            if (chunk.getChecksum() != null && !chunk.getChecksum().isEmpty()) {
                                MessageDigest digest = MessageDigest.getInstance("SHA-256");
                                String computed = HexFormat.of().formatHex(digest.digest(content));
                                if (!MessageDigest.isEqual(
                                        computed.getBytes(),
                                        chunk.getChecksum().getBytes())) {
                                    throw new SecurityException("Chunk checksum mismatch");
                                }
                            }

                            outputStream.write(content);
                        }
                    } catch (Exception e) {
                        logger.log(Level.SEVERE, "Error writing chunk", e);
                    }
                }

                @Override
                public void onError(Throwable t) {
                    logger.log(Level.SEVERE, "Download failed", t);
                    latch.countDown();
                }

                @Override
                public void onCompleted() {
                    logger.info("Download completed");
                    latch.countDown();
                }
            });
        }

        if (!latch.await(5, TimeUnit.MINUTES)) {
            logger.warning("Download timed out");
        }
    }

    public void shutdown() throws InterruptedException {
        channel.shutdown().awaitTermination(10, TimeUnit.SECONDS);
        if (!channel.isTerminated()) {
            channel.shutdownNow();
        }
    }
}